/**
 * Single source of truth for company-specific values.
 *
 * Every value can be overridden per-instance with a VITE_COMPANY_* env var.
 * With no env vars set, defaults produce the AMP instance exactly as before —
 * so our own deployment needs zero configuration changes.
 *
 * To stand up a new customer instance, set these in the instance's .env /
 * Netlify environment; do not edit this file.
 */

const env = import.meta.env;

/** Vite types env values as string | boolean; only accept non-empty strings. */
const str = (value: unknown, fallback: string): string =>
  typeof value === "string" && value ? value : fallback;

/** Split a comma-separated env var into a trimmed string array. */
const list = (value: unknown, fallback: string[]): string[] =>
  typeof value === "string" && value
    ? value.split(",").map((s) => s.trim()).filter(Boolean)
    : fallback;

