/** Brand hex values for JS contexts where CSS variables can't be used
 * (detached print/PDF documents, hex-with-alpha-suffix tricks).
 * `let` on purpose: applyBrandColorValues updates them when an admin-saved
 * theme loads, and ES module live bindings propagate to importers. */
export let BRAND_COLOR = companyConfig.brandColor;
export let BRAND_COLOR_DARK = companyConfig.brandColorDark;

const hexToRgbTriple = (hex: string): string => {
  const h = hex.replace("#", "");
  const n = parseInt(
    h.length === 3 ? h.split("").map((c) => c + c).join("") : h,
    16
  );
  return `${(n >> 16) & 255} ${(n >> 8) & 255} ${n & 255}`;
};

/**
 * Push a pair of brand colors into CSS variables on <html> so Tailwind's
 * `brand` palette and any `var(--brand)` styles pick them up.
 * Used at boot with the env/default colors and by the admin Website Theme
 * page for DB-saved overrides and live preview.
 */
export const applyBrandColorValues = (brand: string, dark: string): void => {
  BRAND_COLOR = brand;
  BRAND_COLOR_DARK = dark;
  const root = document.documentElement.style;
  root.setProperty("--brand", brand);
  root.setProperty("--brand-rgb", hexToRgbTriple(brand));
  root.setProperty("--brand-dark", dark);
  root.setProperty("--brand-dark-rgb", hexToRgbTriple(dark));
};

/** Apply the env/default brand colors. Call once at app boot (main.tsx). */
export const applyBrandColors = (): void =>
  applyBrandColorValues(BRAND_COLOR, BRAND_COLOR_DARK);

/** Darken a hex color by the given factor (0–1); used to derive the hover shade. */
export const darkenHex = (hex: string, factor = 0.12): string => {
  const h = hex.replace("#", "");
  const full = h.length === 3 ? h.split("").map((c) => c + c).join("") : h;
  const n = parseInt(full, 16);
  const scale = (v: number) => Math.max(0, Math.round(v * (1 - factor)));
  const [r, g, b] = [scale((n >> 16) & 255), scale((n >> 8) & 255), scale(n & 255)];
  return `#${((r << 16) | (g << 8) | b).toString(16).padStart(6, "0")}`;
};

/** Placeholder like "your@ampqes.com" built from the first allowed domain. */
export const emailPlaceholder = `your${companyConfig.allowedEmailDomains[0] || "@example.com"}`;

/** Regex matching an employee email on any allowed domain. */
export const employeeEmailRegex = new RegExp(
  `(${companyConfig.allowedEmailDomains
    .map((d) => d.replace(".", "\\."))
    .join("|")})$`,
  "i"
);

/**
 * Regex capturing first/last name from a first.last@<allowed-domain> email.
 * Match groups 1 and 2 are the first and last name.
 */
export const employeeNameEmailRegex = new RegExp(
  `^([a-z]+)\\.([a-z]+)(${companyConfig.allowedEmailDomains
    .map((d) => d.replace(".", "\\."))
    .join("|")})$`,
  "i"
);
